10	export type ItemType = keyof typeof BASE_PREMIUM;
11	
12	export type Item = { type: ItemType; cursed?: boolean; enchantment?: number };
13	
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	const COMPONENT_TYPES: ReadonlySet<ItemType> = new Set<ItemType>(["rune", "moonstone"]);
17	const LOYALTY_YEARS_THRESHOLD = 2;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const CURSED_SURCHARGE_RATE = 0.5;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
23	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
24	const PROCESSING_FEE = 5;
25	
26	function itemSurcharge(item: Item): number {
27	  const base = BASE_PREMIUM[item.type];
28	  const cursed = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
29	  const enchantment =
30	    item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
31	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
32	      : 0;
33	  return cursed + enchantment;
34	}
35	
36	export function calculatePremium(items: Item[], customer?: { yearsWithMHPCO: number }, options?: { isFollowUp?: boolean }): number {
37	  const groups = new Map<ItemType, number>();
38	  let totalSurcharge = 0;
39	  for (const item of items) {
40	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
41	    totalSurcharge += itemSurcharge(item);
42	  }
43	
44	  let total = 0;
45	  for (const [type, count] of groups) {
46	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
47	      total += BLOCK_PREMIUM;
48	    } else {
49	      total += count * BASE_PREMIUM[type];
50	    }
51	  }
52	  let policyPremium = total + totalSurcharge;
53	  if (customer && customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD) {
54	    policyPremium *= 1 - LOYALTY_DISCOUNT_RATE;
55	  }
56	  policyPremium += policyPremium * FIRST_INSURANCE_SURCHARGE_RATE;
57	  if (options?.isFollowUp) {
58	    policyPremium *= 1 - FOLLOW_UP_DISCOUNT_RATE;
59	  }
60	  return policyPremium + PROCESSING_FEE;
61	}
